require.config({
  paths: {
    '@xwiki/platform-guidedtour-xwiki': $jsontool.serialize($services.webjars.url('org.xwiki.platform:xwiki-platform-guidedtour-node-ui', 'index.es.js'))
  }
});

require(['@xwiki/platform-guidedtour-xwiki'], function (gt) {
  console.info(gt);
  // Simple interactivity: load properties when clicking sidebar items
  const stepsListContainer = document.querySelector('.stepsListContainer');
  console.warn(stepsListContainer.dataset.steps)
  const steps = JSON.parse(stepsListContainer.dataset.steps);
  const items = document.querySelectorAll('.item');
  function loadItem(id) {
    const data = steps[id];
    if (!data) return;
    document.querySelectorAll('.item').forEach(i => i.classList.toggle('active', i.dataset.id == String(id)));
    document.querySelectorAll('.itemDisplay').forEach(i => i.classList.toggle('hidden', i.id != "XWiki.GuidedTour.StepClass_" + String(id)));
  }

  function reorderItems() {
    const children = document.querySelectorAll('.item');
    const itemList = document.querySelectorAll('.item-list');
  }

  items.forEach(i => i.addEventListener('click', () => loadItem(i.dataset.id)));
  // load first item by default
  loadItem(0);
  //new FormData(formElement)
  // Add listener for order changes, to reorder the steps in the UI XWiki.GuidedTour.StepClass_0_order
  const addStepButton = document.querySelector('#add-step-btn');
  const formKeyRegex = /^XWiki.GuidedTour.StepClass_(\d+)_(\S+)$/;
  if (addStepButton) {
    addStepButton.addEventListener('click', (e) => {
      e.preventDefault();
      // FIXME: This selector is brittle, but idk how else to get all the necessary data (and overwrite the actual save to not do any step updates)
      let a = document.createElement('input');
      a.id = 'addedObjects'
      a.value = ['XWiki.GuiedTour.StepClass_1']
      a.classList.add('hidden')
      document.querySelector('form#inline').appendChild(a)
      const formData = new FormData(document.querySelector('form#inline'));
      console.info(steps)
      for (let formKey of formData.keys()) {
        const matches = formKey.match(formKeyRegex);
        if (matches) {
          const stepIdx = Number.parseInt(matches[1]);
          const prop = matches[2];
          if (stepIdx >= steps.length) {
            // This is a new added step.
            steps.push({})
          }
          steps[stepIdx][prop] = formData.get(formKey)
        }
      }
      console.info(steps)
      // formData.set('addedObjects', 'XWiki.GuidedTour.StepClass_1'); // This doesn't work.
      console.warn('clicked', e, formData);
    });
  }
  document.on('xwiki:actions:beforeSave', (e) => {
    // e.preventDefault();
    // request.set('addedObjects', ['XWiki.GuidedTour.StepClass_6'])
    // request.set('deletedObjects', ['XWiki.GuidedTour.StepClass_6'])
    console.error('before save', e);
  });
});

:root{
  --sidebar-w: 260px;
  --bg: #f6f7fb;
  --card: #ffffff;
  --muted: #727272;
  --accent: #2563eb;
  --radius: 10px;
  --gap: 20px;
  font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
}

.stepsListContainer{
  display:flex;
  gap:var(--gap);
  align-items:flex-start;
  margin:0 auto;
  width:100%;
}

/* Sidebar */
.stepsListContainer .sidebar{
  width:var(--sidebar-w);
  border-radius:var(--radius);
  padding:16px;
  flex-shrink:0;
  border: solid var(--muted);
}

.stepsListContainer .sidebar-title{
  margin:0 0 12px 0;
  font-size:14px;
  color:var(--muted);
}

.stepsListContainer .item-list{
  list-style:none;
  padding:0;
  margin:0;
  display:flex;
  flex-direction:column;
  gap:8px;
}

.stepsListContainer .item{
  padding:10px 12px;
  border-radius:8px;
  cursor:pointer;
  background:transparent;
  color:#0f172a;
  align-items:center;
  justify-content:space-between;
  transition:all .12s ease;
  border:1px solid transparent;
  max-width: 100%;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  display: block;
}

.stepsListContainer .item:hover{
  transform:translateY(-2px);
  box-shadow:0 4px 10px rgba(16,24,40,0.06);
}

.stepsListContainer .item.active{
  background:linear-gradient(90deg, rgba(37,99,235,0.08), rgba(37,99,235,0.04));
  border-color:rgba(37,99,235,0.18);
  color:var(--accent);
  font-weight:600;
}

/* Content (form area) */
.container .content{
  flex:1;
  background:var(--card);
  padding:20px;
  border-radius:var(--radius);
  min-height:320px;
}

.container .content-title{
  margin:0 0 16px 0;
  font-size:18px;
}

.container .props-form{
  display:grid;
  grid-template-columns:repeat(2, minmax(0,1fr));
  gap:12px 20px;
  align-items:start;
}

.container .field{
  display:flex;
  flex-direction:column;
  gap:8px;
}

.container .field label{
  font-size:13px;
  color:var(--muted);
}

.field input[type="text"],
.field select,
.field textarea{
  padding:10px 12px;
  border-radius:8px;
  border:1px solid #e6e9ef;
  background:#fff;
  font-size:14px;
  outline:none;
  transition:border-color .12s ease, box-shadow .12s ease;
}

.field input[type="text"]:focus,
.field select:focus,
.field textarea:focus{
  border-color:rgba(37,99,235,0.6);
  box-shadow:0 4px 10px rgba(37,99,235,0.08);
}

.field input[type="checkbox"]{
  width:18px;
  height:18px;
  transform:translateY(4px);
}

/* Make description span full width */
.field textarea{
  resize:vertical;
  min-height:88px;
  grid-column:1 / -1;
}

/* Actions row spans full width */
.container .actions{
  grid-column:1 / -1;
  display:flex;
  gap:10px;
  justify-content:flex-start;
  margin-top:6px;
}
/* Responsive */
@media (max-width:880px){
  .container{flex-direction:column}
  .sidebar{width:100%}
  .props-form{grid-template-columns:1fr}
  .field textarea{grid-column:1/1}
  .actions{justify-content:stretch}
}
